**Playwright Kurulum:** `npm install playwright && npx playwright install`. ```js
const { chromium } = require('playwright');
(async () => {
  const b = await chromium.launch();
  const p = await b.newPage();
  await p.goto('https://site.com');
  await p.waitForSelector('.item');
  const data = await p.$$eval('.item', els => els.map(e => e.textContent));
  console.log(data);
  await b.close();
})();
``` Playwright > Selenium: hızlı, modern API, auto-wait.

**Puppeteer Snapshot:** ```js
const puppeteer = require('puppeteer');
(async () => {
  const browser = await puppeteer.launch();
  const page = await browser.newPage();
  await page.goto('https://site.com', {waitUntil:'networkidle2'});
  await page.screenshot({path:'shot.png', fullPage:true});
  await page.pdf({path:'page.pdf', format:'A4'});
  await browser.close();
})();
``` Ekran görüntüsü + PDF oluşturma + CSS enjeksiyonu + form doldurma.

**Saygılı Scraping: Rate Limiting Stratejileri**

Sunucuya zarar vermeden veri toplamak için gecikme, backoff ve kota yönetimi teknikleri.

**Akıllı Rate Limiter:**
```python
import time
import random
from functools import wraps

def rate_limited(min_delay=1.0, max_delay=3.0):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            delay = random.uniform(min_delay, max_delay)
            time.sleep(delay)
            return func(*args, **kwargs)
        return wrapper
    return decorator

@rate_limited(min_delay=1.5, max_delay=4.0)
def fetch_page(url, session):
    return session.get(url, timeout=15)
```

**Exponential Backoff:**
```python
import requests
from tenacity import retry, wait_exponential, stop_after_attempt

@retry(
    wait=wait_exponential(multiplier=1, min=2, max=60),
    stop=stop_after_attempt(5)
)
def robust_get(url):
    resp = requests.get(url, timeout=10)
    resp.raise_for_status()  # 4xx/5xx → retry
    return resp
```

**Kota Yönetimi:**
```python
from collections import deque
import time

class RateLimiter:
    def __init__(self, max_calls, period=60):
        self.max_calls = max_calls
        self.period = period
        self.calls = deque()

    def __call__(self):
        now = time.monotonic()
        # Period dışı çağrıları temizle
        while self.calls and self.calls[0] <= now - self.period:
            self.calls.popleft()
        if len(self.calls) >= self.max_calls:
            sleep_time = self.period - (now - self.calls[0])
            time.sleep(sleep_time)
        self.calls.append(now)
```
